import{_ as r,o as a,c as e,ae as l}from"./chunks/framework.BeMCGcrk.js";const c=JSON.parse('{"title":"小米集团(01810.HK)深度分析报告","description":"","frontmatter":{},"headers":[],"relativePath":"blog/xiaomi-2026-analysis.md","filePath":"blog/xiaomi-2026-analysis.md"}'),o={name:"blog/xiaomi-2026-analysis.md"};function i(d,t,n,h,s,g){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="小米集团-01810-hk-深度分析报告" tabindex="-1">小米集团(01810.HK)深度分析报告 <a class="header-anchor" href="#小米集团-01810-hk-深度分析报告" aria-label="Permalink to &quot;小米集团(01810.HK)深度分析报告&quot;">​</a></h1><p><strong>看多 | 目标价：40港元 | 评级：买入</strong></p><p><em>2026年3月16日</em></p><hr><h2 id="一、核心观点" tabindex="-1">一、核心观点 <a class="header-anchor" href="#一、核心观点" aria-label="Permalink to &quot;一、核心观点&quot;">​</a></h2><p><strong>看多小米</strong>，短期回调是机会。理由：</p><ol><li><strong>汽车业务爆发增长</strong>：2026年2月交付超2万台，YU7稳坐中大型SUV销冠</li><li><strong>新产品周期</strong>：新一代SU7将于4月上市，改款升级有望引爆销量</li><li><strong>估值处于低位</strong>：较高点回调超18%，已反映市场悲观预期</li><li><strong>长期生态协同</strong>：手机×汽车×IoT形成完整生态壁垒</li></ol><hr><h2 id="二、股价表现" tabindex="-1">二、股价表现 <a class="header-anchor" href="#二、股价表现" aria-label="Permalink to &quot;二、股价表现&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>当前股价（3月13日）</td><td>33.32港元</td></tr><tr><td>2026年涨跌幅</td><td>-18.58%</td></tr><tr><td>总市值</td><td>约8366亿港元</td></tr></tbody></table><p><strong>解读</strong>：年初至今跌幅较大，主要受两方面影响：</p><ul><li>智能手机需求疲软</li><li>投行下调目标价</li></ul><p>但当前估值已具备吸引力。</p><hr><h2 id="三、汽车业务分析" tabindex="-1">三、汽车业务分析 <a class="header-anchor" href="#三、汽车业务分析" aria-label="Permalink to &quot;三、汽车业务分析&quot;">​</a></h2><h3 id="交付数据" tabindex="-1">交付数据 <a class="header-anchor" href="#交付数据" aria-label="Permalink to &quot;交付数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>月份</th><th>交付量</th><th>主力车型</th></tr></thead><tbody><tr><td>2026年2月</td><td>20,000+台</td><td>YU7</td></tr><tr><td>2026年1月</td><td>37,869台</td><td>YU7（销冠）</td></tr><tr><td>2025年全年</td><td>SU7销冠</td><td>20万+轿车细分第一</td></tr></tbody></table><h3 id="新品预期" tabindex="-1">新品预期 <a class="header-anchor" href="#新品预期" aria-label="Permalink to &quot;新品预期&quot;">​</a></h3><ul><li><strong>新一代SU7</strong>：预计2026年4月上市</li><li>首次改款：听取车主建议，细节全面升级</li><li>新颜色「卡布里蓝」亮相</li></ul><h3 id="投资亮点" tabindex="-1">投资亮点 <a class="header-anchor" href="#投资亮点" aria-label="Permalink to &quot;投资亮点&quot;">​</a></h3><ol><li><strong>产能爬坡成功</strong>：淡季交付超2万，验证供应链能力</li><li><strong>YU7热销</strong>：中大型SUV连续5个月销冠，产品力获验证</li><li><strong>品牌势能</strong>：20万以上轿车市场No.1，消费者认可度高</li></ol><hr><h2 id="四、手机业务" tabindex="-1">四、手机业务 <a class="header-anchor" href="#四、手机业务" aria-label="Permalink to &quot;四、手机业务&quot;">​</a></h2><h3 id="风险点" tabindex="-1">风险点 <a class="header-anchor" href="#风险点" aria-label="Permalink to &quot;风险点&quot;">​</a></h3><ul><li><strong>利润率压力</strong>：摩根大通预计Q4 2025毛利率降至8-9%</li><li>原因：记忆体成本上涨</li><li>投行维持「中性」评级，目标价35港元</li></ul><h3 id="机遇" tabindex="-1">机遇 <a class="header-anchor" href="#机遇" aria-label="Permalink to &quot;机遇&quot;">​</a></h3><ul><li><strong>高端化持续</strong>：小米15系列站稳高端市场</li><li><strong>海外扩张</strong>：欧洲、东南亚市场渗透率提升</li><li><strong>AI赋能</strong>：澎湃OS生态协同效应显现</li></ul><hr><h2 id="五、机构观点" tabindex="-1">五、机构观点 <a class="header-anchor" href="#五、机构观点" aria-label="Permalink to &quot;五、机构观点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>机构</th><th>评级</th><th>目标价</th><th>观点</th></tr></thead><tbody><tr><td>摩根大通</td><td>中性</td><td>35港元</td><td>利润率压力待解</td></tr><tr><td>花旗</td><td>待确认</td><td>下调</td><td>短期承压</td></tr><tr><td>市场预期</td><td>-</td><td>35-40港元</td><td>中性偏多</td></tr></tbody></table><p><strong>解读</strong>：机构偏谨慎，但目标价与现价33港元仍有空间。</p><hr><h2 id="六、估值分析" tabindex="-1">六、估值分析 <a class="header-anchor" href="#六、估值分析" aria-label="Permalink to &quot;六、估值分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>市盈率（TTM）</td><td>约25倍</td></tr><tr><td>市净率</td><td>约4.5倍</td></tr><tr><td>目标价</td><td>40港元</td></tr><tr><td>上涨空间</td><td>20%</td></tr></tbody></table><p>对比行业平均30倍PE，小米的汽车业务尚未完全反映在估值中，存在明显折价。</p><hr><h2 id="七、风险提示" tabindex="-1">七、风险提示 <a class="header-anchor" href="#七、风险提示" aria-label="Permalink to &quot;七、风险提示&quot;">​</a></h2><ol><li><strong>价格战加剧</strong>：新能源车企价格战持续</li><li><strong>成本压力</strong>：芯片、电池成本波动</li><li><strong>竞争加剧</strong>：比亚迪、吉利等加速追赶</li><li><strong>汽车盈利</strong>：尚未实现规模盈利</li></ol><hr><h2 id="八、结论" tabindex="-1">八、结论 <a class="header-anchor" href="#八、结论" aria-label="Permalink to &quot;八、结论&quot;">​</a></h2><p><strong>操作建议：买入</strong></p><ul><li><strong>建仓区间</strong>：30-33港元</li><li><strong>第一目标</strong>：38港元</li><li><strong>第二目标</strong>：40港元</li><li><strong>止损位</strong>：28港元</li></ul><p>短期回调不改长期逻辑。汽车业务已证明能力，新品周期将带动估值修复。当前位置具备较高赔率，适合分批布局。</p><hr><p><em>免责声明：本报告仅供参考，不构成投资建议。股市有风险，入市需谨慎。</em></p><p><strong>参考来源</strong>：</p><ol><li><a href="https://www.163.com/dy/article/KN8FGBIJ0552NVEU.html" target="_blank" rel="noreferrer">小米股价年初至今累计跌超18%，多家机构下调目标价</a></li><li><a href="https://www.ithome.com/0/924/715.htm" target="_blank" rel="noreferrer">小米汽车2月交付量超20000台</a></li><li><a href="https://news.futunn.com/post/69499230/jpmorgan-xiaomi-01810-hk-faces-increasing-margin-pressure-downgrades-target" target="_blank" rel="noreferrer">摩根大通：利润率压力加剧</a></li><li><a href="https://m.163.com/dy/article/KJBF359B0511B8LM.html" target="_blank" rel="noreferrer">小米YU7销量夺冠</a></li></ol>',47)])])}const u=r(o,[["render",i]]);export{c as __pageData,u as default};
